import './App.css';
import { Link, Route, Routes } from 'react-router-dom';
import Home from './components/side _nav/1';
import About from './components/Header/Header';
import Header from './components/Header/Header';


function App() {
  return (
    <>
    <div className='header'>
    <Header/>
    </div>
    <div className='container'>
          <nav className='sidenav'>
            <ul>
              <li><Link to="/1">1</Link><br></br></li> {" "}
              <li><Link to="/2">2</Link><br></br></li>
              <li><Link to="/3">3</Link><br></br></li>
              <li><Link to="/4">4</Link><br></br></li>
              <li><Link to="/5">5</Link><br></br></li>
              <li><Link to="/6">6</Link><br></br></li>
              <li><Link to="/7">7</Link><br></br></li>
              <li><Link to="/8">8</Link><br></br></li>
              <li><Link to="/9">9</Link><br></br></li>
            </ul>
          </nav>


          <div  className='maincontent'>
          <Routes>
              <Route path="/" element={<Home />} />
              <Route path="/about" element={<About/>} />
          </Routes>
          </div>
    </div>
    <div  className='footer'>
          <h1>Footer</h1>
    </div>
    </>
  );
}

export default App;
